"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[9086],{6572:(e,a,i)=>{i.d(a,{S:()=>t});let t=229},8971:(e,a,i)=>{i.d(a,{M:()=>t,q:()=>r});let t=[{id:"ancient",label:"Ancient & Pre-Digital",years:"~20,000 BC – 1843",icon:"\uD83C\uDFDB️",color:"#f59e0b"},{id:"theory",label:"Information Theory",years:"1936 – 1955",icon:"\uD83D\uDCD0",color:"#06b6d4"},{id:"ai1",label:"Birth of AI",years:"1951 – 1979",icon:"\uD83E\uDD16",color:"#a78bfa"},{id:"hardware",label:"Hardware Revolution",years:"1971 – 1995",icon:"\uD83D\uDD27",color:"#10b981"},{id:"ml",label:"Machine Learning Era",years:"1986 – 2012",icon:"\uD83E\uDDE0",color:"#ec4899"},{id:"deep",label:"Deep Learning Revolution",years:"2012 – 2020",icon:"\uD83D\uDD2C",color:"#9F8CFF"},{id:"gen",label:"Generative AI Explosion",years:"2021 – 2023",icon:"\uD83D\uDE80",color:"#ef4444"},{id:"agents",label:"Agentic AI & Frontier",years:"2024 – Now",icon:"⚡",color:"#fbbf24"}],r=[{id:"ishango",era:"ancient",yearNum:-2e4,year:"~20,000 BC",emoji:"\uD83E\uDDB4",title:"Ishango Bone — First Mathematical Artifact",by:"Congo Basin, Democratic Republic of Congo",desc:"A baboon fibula with notch groups consistent with an arithmetic series and prime numbers (11, 13, 17, 19). Considered the world's oldest mathematical artifact — proof that humans encoded numerical patterns long before writing.",significance:"The first physical evidence of systematic numerical encoding — the conceptual origin of all information processing.",tags:["Mathematics","Counting","Prime Series"]},{id:"abacus",era:"ancient",yearNum:-2700,year:"~2700 BC",emoji:"\uD83E\uDDEE",title:"Sumerian Abacus — First Calculation Device",by:"Mesopotamia (modern Iraq & Syria)",desc:"Sumerians developed the abacus (~2700–2300 BC), using columns to represent orders of magnitude. Spread rapidly to Egypt, Persia, Greece, China. First 'outsourcing' of mental arithmetic to a physical device. Romans later standardized it for taxation and trade.",significance:"First human + machine collaboration for computation. Remained in daily use for 4,000+ years.",tags:["Mechanical Calc","Arithmetic","Commerce"],links:[{label:"From Abacus to AI ↗",url:"https://www.toolify.ai/ai-news/from-abacus-to-ai-the-evolution-of-computing-1388924"}]},{id:"antikythera",era:"ancient",yearNum:-100,year:"~150–87 BC",emoji:"⚙️",title:"Antikythera Mechanism — World's First Analog Computer",by:"Unknown Greek engineers, Corinthian colony",desc:"A bronze clockwork of at least 37 precision gears that predicted eclipse cycles, tracked 5 planets, and modeled the Metonic calendar. CT-scan analysis (2006) revealed epicyclic gearing with gear ratios matching modern astronomical constants. Nothing comparable appeared for 1,400 years.",significance:"Proved 'computers' predate electricity by 2,000 years. Demonstrated that mechanical information processing was possible in antiquity.",tags:["Analog Computer","37 Bronze Gears","Astronomy","First Computer"],links:[{label:"Smithsonian Magazine ↗",url:"https://www.smithsonianmag.com/history/decoding-antikythera-mechanism-first-computer-180953979/"}]},{id:"leibniz",era:"ancient",yearNum:1685,year:"1673–1703",emoji:"\uD83D\uDD22",title:"Leibniz's Stepped Reckoner & Binary Arithmetic",by:"Gottfried Wilhelm Leibniz, Leipzig, Germany",desc:"First mechanical calculator handling multiplication and division. Leibniz also independently developed binary arithmetic (0s and 1s) in 1703 — influenced by the I Ching. Binary is the mathematical foundation of every modern computer, smartphone, and AI model.",significance:"Binary number system + mechanical calculation = the mathematical DNA of all digital computing.",tags:["Binary Math","Multiplication","Mechanical"]},{id:"babbage",era:"ancient",yearNum:1843,year:"1837–1843",emoji:"\uD83C\uDFED",title:"Analytical Engine & Ada Lovelace — First Computer Program",by:"Charles Babbage & Ada Lovelace, London, UK",desc:"Babbage designed a mechanical general-purpose computer with separate 'mill' (CPU) and 'store' (memory) — the full von Neumann architecture 100 years early. Ada Lovelace wrote Algorithm #1 (Bernoulli numbers) in 1843 — the world's first computer program — and predicted machines could compose music.",significance:"The conceptual blueprint for every computer ever built. Lovelace's note that machines could handle 'any relation that can be expressed by numbers' prefigured AGI thinking.",tags:["CPU + Memory","I/O Architecture","First Algorithm","First Programmer"]},{id:"turing-machine",era:"theory",yearNum:1936,year:"1936",emoji:"\uD83D\uDDA5️",title:"Turing Machine — Defines Computation Itself",by:"Alan Turing, Proceedings of the London Mathematical Society",desc:"Turing described a theoretical 'universal machine' that can simulate any algorithm by reading and writing symbols on an infinite tape. He also proved the Halting Problem is unsolvable — establishing the fundamental limits of computation before computers existed.",significance:"Defined the mathematical foundation of all software, algorithms, and AI. Every computer program is a Turing machine at its core.",tags:["Theory of Computation","Algorithms","Halting Problem"]},{id:"eniac",era:"theory",yearNum:1946,year:"1945–1946",emoji:"\uD83D\uDCBB",title:"ENIAC — World's First General-Purpose Electronic Computer",by:"Eckert & Mauchly, University of Pennsylvania, Philadelphia",desc:"18,000 vacuum tubes, 30 tons, occupying 1,800 sq ft. Could perform 5,000 additions per second — replacing 100 trained humans working a year on ballistics tables. First run was classified. The Computer History Museum notes it 'may have run more calculations than all of humanity had done up to that point.'",significance:"First moment in history when machines could outcompute humans at scale. The start of the Information Age.",tags:["18,000 Vacuum Tubes","30 Tons","5,000 add/sec"],links:[{label:"Computer History Museum ↗",url:"https://www.computerhistory.org/revolution/birth-of-the-computer/4/78"}]},{id:"transistor",era:"theory",yearNum:1947,year:"Dec 1947",emoji:"\uD83D\uDD2C",title:"Transistor Invented at Bell Labs",by:"Shockley, Bardeen & Brattain — Bell Laboratories, Murray Hill, NJ",desc:"Replaced vacuum tubes with a tiny solid-state amplifier/switch. Won the 1956 Nobel Prize in Physics. Transistors shrank from millimeter-scale to sub-5nm — over 100,000\xd7 reduction. Apple's M3 Ultra (2024) contains 153 billion transistors. Without the transistor, there are no microchips, no internet, no AI.",significance:"The physical atom of the digital age. Moore's Law is entirely about transistors doubling every ~18 months for 50 years straight.",tags:["Hardware","Semiconductor","Nobel Prize 1956","Foundation of All Chips"]},{id:"shannon",era:"theory",yearNum:1948,year:"1948",emoji:"\uD83D\uDCE1",title:"Shannon — 'A Mathematical Theory of Communication'",by:"Claude Shannon, Bell Laboratories, NJ",desc:"Shannon proved that information is measurable, introduced the 'bit' as the fundamental unit, showed how to transmit data reliably over noisy channels via redundancy, and defined channel capacity. Scientific American: 'The Magna Carta of the Information Age.'",significance:"Created the theoretical bedrock of all digital technology — the internet, mobile phones, WiFi, streaming video, and AI data pipelines. Without Shannon, none of it exists.",tags:["The Bit","Entropy","Channel Capacity","Digital Communication"],links:[{label:"Bell Labs 75th ↗",url:"https://www.nokia.com/bell-labs/about/history/innovation-stories/information-theory-turns-75/"}]},{id:"turing-test",era:"theory",yearNum:1950,year:"1950",emoji:"\uD83E\uDD14",title:"Turing Test — 'Can Machines Think?'",by:"Alan Turing, Mind Journal, Oxford",desc:"Turing asked 'Can machines think?' and proposed the Imitation Game: if a human interrogator can't distinguish a machine's text responses from a human's, the machine passes. A 2023 Stanford study found GPT-4 passed in specific settings — exactly 73 years after the paper.",significance:"Defined the fundamental question of AI for 70+ years — and the goalposts we're now moving past.",tags:["AI Philosophy","Imitation Game","Intelligence Test","GPT-4 Passed 2023"]},{id:"snarc",era:"ai1",yearNum:1951,year:"1951",emoji:"\uD83E\uDDEC",title:"SNARC — First Artificial Neural Network Machine",by:"Marvin Minsky, Princeton / Harvard, USA",desc:"Minsky built the first physical artificial neural network — 3,000 vacuum tubes simulating 40 neurons with adjustable synaptic weights. Implemented McCulloch & Pitts' 1943 theoretical neuron model in hardware. The direct ancestor of every deep learning system today.",significance:"First hardware neural network — 70+ years before GPT-4 would run on the same underlying mathematical principle.",tags:["Neural Network","40 Artificial Neurons","3,000 Vacuum Tubes"]},{id:"dartmouth",era:"ai1",yearNum:1956,year:"Summer 1956",emoji:"\uD83C\uDF93",title:"Dartmouth Conference — AI is Born as a Science",by:"McCarthy, Minsky, Shannon, Rochester — Dartmouth College, Hanover NH",desc:"John McCarthy organized a 6-week summer research project at Dartmouth, coining the term 'Artificial Intelligence.' Proposal: 'every aspect of learning or any other feature of intelligence can in principle be so precisely described that a machine can be made to simulate it.'",significance:"'The founding moment of artificial intelligence as a field of research.' — Dartmouth College official record.",tags:["AI Founded","Term Coined","Symbolic AI"],links:[{label:"Dartmouth Official ↗",url:"https://home.dartmouth.edu/about/artificial-intelligence-ai-coined-dartmouth"}]},{id:"perceptron",era:"ai1",yearNum:1958,year:"1958",emoji:"\uD83D\uDD01",title:"Perceptron — First Trainable Neural Network",by:"Frank Rosenblatt, Cornell Aeronautical Lab, Buffalo NY",desc:"The perceptron could learn from examples by adjusting synaptic weights based on errors — the first learning algorithm. New York Times predicted it would 'walk, talk, see, write, reproduce itself.' Cornell's 2019 retrospective called it 'paved the way for AI, 60 years too soon.'",significance:"Origin of all machine learning — the concept that intelligence could emerge from iteratively adjusting weights on labeled data.",tags:["Learning","Weight Adjustment","Pattern Recognition"],links:[{label:"Cornell Retrospective ↗",url:"https://news.cornell.edu/stories/2019/09/professors-perceptron-paved-way-ai-60-years-too-soon"}]},{id:"moores-law",era:"ai1",yearNum:1965,year:"April 1965",emoji:"\uD83D\uDCCF",title:"Moore's Law — Engine of Exponential Progress",by:"Gordon Moore, Fairchild Semiconductor — Electronics Magazine",desc:"Moore observed transistors per chip doubled annually (revised to ~18 months in 1975). Held true 50+ years: from 2,300 transistors (Intel 4004, 1971) to 153 billion (Apple M3 Ultra, 2024). This exponential compute growth directly caused deep learning to become economically feasible.",significance:"The self-fulfilling prophecy that made AI inevitable — it took 50 years of transistor doublings to create hardware powerful enough to train GPT-3.",tags:["Exponential Growth","Transistors","50-Year Trend"],links:[{label:"Our World in Data ↗",url:"https://ourworldindata.org/moores-law"}]},{id:"eliza",era:"ai1",yearNum:1966,year:"1966",emoji:"\uD83D\uDCAC",title:"ELIZA — World's First Chatbot",by:"Joseph Weizenbaum, MIT AI Lab, Cambridge MA",desc:"ELIZA simulated a psychotherapist using pattern matching and scripted responses. Users reported genuine emotional connection — alarming creator Weizenbaum, who warned about anthropomorphizing AI. The 'ELIZA Effect' describes the human tendency to project understanding onto AI systems — still highly relevant in 2026.",significance:"First natural language human-computer interaction. The direct ancestor of ChatGPT — separated by 57 years and a trillion parameters.",tags:["Chatbot","NLP","Rogerian Therapy","ELIZA Effect"]},{id:"intel4004",era:"hardware",yearNum:1971,year:"Nov 1971",emoji:"\uD83E\uDDE9",title:"Intel 4004 — First Commercial Microprocessor",by:"Intel (Hoff, Mazor, Faggin)",desc:"General-purpose programmable processor on a single chip. 2,300 transistors, 740 kHz. By 2024, Apple's M3 Ultra: 153 billion transistors — a 66-million-fold increase in 53 years. Enabled PCs (1975+), internet, mobile, and AI hardware.",significance:"Put computing inside everything — the hardware engine for every computer, smartphone, server, and AI accelerator ever built.",tags:["2,300 Transistors","740 kHz","4-bit CPU"]},{id:"expert-systems",era:"hardware",yearNum:1980,year:"1965–1987",emoji:"\uD83E\uDDE0",title:"Expert Systems Era & AI Winters",by:"Edward Feigenbaum (Stanford) — DENDRAL, MYCIN, R1/XCON",desc:"DENDRAL identified organic molecules; MYCIN diagnosed bacterial infections better than medical students. Generated a $500M commercial industry by 1985. But expert systems were brittle. Two major 'AI Winters' (1974, 1987) followed waves of overpromising. Each winter ended when a new technical breakthrough arrived.",significance:"Proved AI could be commercially valuable — but also taught the field that hard-coded rules cannot scale. Neural networks would prove the lesson 30 years later.",tags:["Rule-Based AI","$500M Industry","AI Winter 1974","AI Winter 1987"]},{id:"internet",era:"hardware",yearNum:1989,year:"1969 / 1989",emoji:"\uD83C\uDF10",title:"ARPANET → Internet → World Wide Web",by:"DARPA (1969) / Tim Berners-Lee at CERN (1989)",desc:"ARPANET (1969) first connected 4 nodes at UCLA, SRI, UCSB, and Utah. Berners-Lee's WWW (1989) turned the internet into a content repository. By the 2010s, the internet's trillion+ pages became the pretraining corpus for every LLM. The Common Crawl dataset (40 billion web pages) is the primary source for GPT, LLaMA, Gemini training.",significance:"Without the internet as a training dataset, there is no ChatGPT. The information highway became AI's classroom.",tags:["Internet","Global Data","LLM Training Data"]},{id:"backprop",era:"ml",yearNum:1986,year:"1986",emoji:"\uD83D\uDD04",title:"Backpropagation — Neural Networks Learn to Learn",by:"Rumelhart, Hinton & Williams — UC San Diego & Carnegie Mellon",desc:"Published in Nature: backpropagation enables neural networks to learn distributed representations by propagating error gradients backward through layers. 'Parallel Distributed Processing' (1986) showed networks could learn language, image features, and logical rules. GPUs were needed to make it practical at scale — which didn't happen until 2012.",significance:"'Backpropagation is foundational to deep learning today.' — Computer History Museum. Every trained AI model on Earth uses this algorithm.",tags:["Gradient Descent","Multi-Layer","All AI Uses This"]},{id:"deep-blue",era:"ml",yearNum:1997,year:"May 1997",emoji:"♟️",title:"IBM Deep Blue Defeats Kasparov",by:"IBM Research (Murray Campbell et al.) — New York City",desc:"Deep Blue evaluated 200 million chess positions per second. Beat reigning world champion Kasparov 3.5–2.5 in a 6-game match. First computer to defeat a world chess champion under tournament conditions. Newsweek called it 'The Brain's Last Stand.'",significance:"First time AI surpassed human experts at complex strategic reasoning — but using brute force, not intelligence. Neural nets would eventually eclipse this approach.",tags:["200M positions/sec","32 Parallel CPUs","World Champion Defeated"],links:[{label:"IBM History ↗",url:"https://www.ibm.com/history/deep-blue"}]},{id:"google",era:"ml",yearNum:1998,year:"Sept 1998",emoji:"\uD83D\uDD0D",title:"Google Founded — Search at Scale, AI at Scale",by:"Larry Page & Sergey Brin — Stanford garage → Menlo Park, CA",desc:"PageRank was itself an early ML algorithm. Google's infrastructure later became the base for Google Brain (2011), TensorFlow (2015), TPUs (2016), BERT (2018), PaLM (2022), AlphaFold, and Gemini. Jeff Dean's MapReduce paper (2004) pioneered distributed computing at AI scale.",significance:"Built the data infrastructure, compute culture, and engineering DNA that produced the Transformer, AlphaFold, and every Gemini model.",tags:["PageRank Algorithm","Data Infrastructure","Deep Learning Birthplace"]},{id:"watson",era:"ml",yearNum:2011,year:"Feb 2011",emoji:"\uD83C\uDFC6",title:"IBM Watson Wins Jeopardy!",by:"IBM Research",desc:"Watson beat champions Brad Rutter and Ken Jennings using statistical NLP across 200M pages of content — including all of Wikipedia. First time NLP AI demonstrated broad knowledge retrieval competitive with top humans on live television. Introduced enterprise AI to the public imagination a decade before ChatGPT.",significance:"'AI' became a household word for the first time — and triggered the first wave of enterprise AI investment.",tags:["NLP","Question Answering","200M Pages","TV Debut of AI"]},{id:"alexnet",era:"deep",yearNum:2012,year:"Oct 2012",emoji:"\uD83D\uDC41️",title:"AlexNet — The Deep Learning Spark",by:"Krizhevsky, Sutskever & Hinton — University of Toronto",desc:"AlexNet won ImageNet with 15.3% error vs 26.2% runner-up — a 41% improvement. 8-layer CNN running on 2\xd7 NVIDIA GTX 580 GPUs. CHM: 'Kicked off today's prevailing approach to AI.' Papers citing AlexNet have been cited over 100,000 times combined — one paper changed an entire field.",significance:"If the Transformer was the architecture, AlexNet was the proof that deep learning worked. It triggered billions in investment and every modern computer vision system.",tags:["CNN","15.3% error → first place","GPU Acceleration","Billion-dollar catalyst"],links:[{label:"CHM: AlexNet ↗",url:"https://computerhistory.org/blog/chm-releases-alexnet-source-code/"}]},{id:"alphago",era:"deep",yearNum:2016,year:"March 2016",emoji:"\uD83C\uDFAE",title:"AlphaGo Defeats Lee Sedol 4–1",by:"DeepMind (Hassabis, Silver) — Seoul, South Korea",desc:"Experts said AI wouldn't beat top Go players for decades — Go has more positions than atoms in the observable universe. AlphaGo used deep RL + self-play + MCTS. Move 37 (Game 2) was described as 'a move no human would play' — a creative, counterintuitive genius move.",significance:"Proved AI could master intuition and long-term planning — not just brute force. Opened the door to RL in robotics, drug discovery, and autonomous systems.",tags:["Reinforcement Learning","Monte Carlo Tree Search","Go Champion","Move 37"]},{id:"transformer",era:"deep",yearNum:2017,year:"June 2017",emoji:"⚡",title:'"Attention Is All You Need" — The Transformer',by:"Vaswani, Shazeer, Parmar + 5 others (all Google Brain) — NeurIPS 2017",desc:"Eight Google Brain engineers replaced RNNs with pure attention mechanisms, enabling full parallelization during training. Every modern LLM (ChatGPT, Claude, Gemini, LLaMA, Grok) is a Transformer. Approaching 100,000 citations. Wired (2024): '8 Google Employees Invented Modern AI.'",significance:"The single most consequential AI paper of the 21st century. The architecture is unchanged in all frontier models in 2026.",tags:["Self-Attention","Parallelization","Foundation of ALL LLMs","100K+ Citations"],links:[{label:"arXiv Paper ↗",url:"https://arxiv.org/abs/1706.03762"},{label:"Wired 2024 ↗",url:"https://www.wired.com/story/eight-google-employees-invented-modern-ai-transformers-paper/"}]},{id:"bert-gpt",era:"deep",yearNum:2018,year:"2018–2019",emoji:"\uD83D\uDCD6",title:"BERT & GPT-1/2 — Pretraining Changes Everything",by:"Google Brain (BERT) / OpenAI (GPT-1/2)",desc:"BERT (2018): bidirectional pretraining achieved SOTA on 11 NLP tasks simultaneously. GPT-2 (1.5B, Feb 2019): OpenAI deemed it 'too dangerous to release' — the staged rollout generated massive press and made AI a mainstream news topic for the first time. The pretrain→finetune paradigm became the template for all AI products.",significance:"Established the 'pretrain on internet text, then fine-tune' paradigm that underlies every commercial AI product today.",tags:["Pretraining","Transfer Learning","117M → 1.5B params"]},{id:"gpt3",era:"deep",yearNum:2020,year:"May 2020",emoji:"\uD83D\uDD24",title:"GPT-3 — 175B Parameters & the Scaling Hypothesis",by:"OpenAI",desc:"GPT-3 generated coherent essays, wrote code, translated languages, and answered complex questions from a few in-prompt examples (few-shot), without fine-tuning. Demonstrated 'emergent capabilities' that weren't trained explicitly. Proved the scaling hypothesis: more compute + more data = qualitatively new abilities. Training cost ~$4.6M.",significance:"First model where scale alone unlocked qualitatively new capabilities — launched the $100B+ investment race to build ever-larger models.",tags:["175B Params","Few-Shot","Emergent Capabilities","Scale = Intelligence"]},{id:"alphafold2",era:"deep",yearNum:2021,year:"2020–2021",emoji:"\uD83E\uDDEC",title:"AlphaFold2 — Solving Biology's Grand Challenge",by:"DeepMind (Hassabis, Jumper & team)",desc:"AlphaFold2 scored 92.4 GDT at CASP14 — solving a 50-year biological grand challenge. The AlphaFold Database grew to 214M structures from 1M+ organisms. Used by 2M+ researchers in 190 countries. Hassabis & Jumper received the 2024 Nobel Prize in Chemistry.",significance:"'Proof that AI will transform science.' — Demis Hassabis. First Nobel Prize awarded for AI-driven scientific discovery.",tags:["Protein Folding Solved","92.4 GDT Score","214M Structures","2024 Nobel Prize"],links:[{label:"DeepMind Nobel ↗",url:"https://deepmind.google/blog/demis-hassabis-john-jumper-awarded-nobel-prize-in-chemistry/"}]},{id:"dalle-codex",era:"gen",yearNum:2021.1,year:"Jan 2021",emoji:"\uD83C\uDFA8",title:"DALL-E & Codex — AI Creates Images & Code",by:"OpenAI",desc:"DALL-E used a discrete VAE to generate images from text prompts. Codex (GPT-3 fine-tuned on GitHub) powered GitHub Copilot — the first commercial AI coding assistant. Copilot reached 1M+ developers within months and was described as 'the most significant developer tool since Google' by some engineers.",significance:"AI stopped being a 'back-end' tool — it started producing visible human-quality outputs in creative fields.",tags:["Text-to-Image","Code Generation","12B params","GitHub Copilot"]},{id:"stable-diffusion",era:"gen",yearNum:2022,year:"2022",emoji:"\uD83D\uDDBC️",title:"Stable Diffusion + Midjourney — Image AI Goes Open",by:"Stability AI / Midjourney (Holz)",desc:"DALL-E 2 (April 2022) brought photorealistic generation. Midjourney (July) democratized AI art via Discord. Stable Diffusion (August) released open-source — anyone with a GPU could generate images. An AI image won the Colorado State Fair art competition (Sept 2022), sparking global debate. Artists filed lawsuits over training data.",significance:"Open-sourcing democratized generative AI overnight — any developer worldwide could build on it, triggering thousands of image tools.",tags:["Diffusion Models","Open Source","Local AI","Art Controversy"]},{id:"chatgpt",era:"gen",yearNum:2022.9,year:"Nov 30, 2022",emoji:"\uD83D\uDCAC",title:"ChatGPT — Fastest Growing Application in History",by:"OpenAI",desc:"1M users in 5 days. 100M in 2 months — shattering TikTok's record (9 months). ChatGPT used GPT-3.5 fine-tuned with RLHF. Microsoft invested $10B shortly after. Google declared a 'code red.' Sam Altman: 'It came out of nowhere to everyone, including us.' Every major company scrambled to launch AI products.",significance:"The moment AI became a consumer reality. 'If AlexNet was the spark, ChatGPT was the explosion that no one saw coming.'",tags:["1M users in 5 days","100M in 2 months","RLHF","Consumer AI Era Begins"]},{id:"gpt4",era:"gen",yearNum:2023.2,year:"March 2023",emoji:"\uD83E\uDDE9",title:"GPT-4 — Professional-Grade Multimodal AI",by:"OpenAI",desc:"GPT-4 passed the bar exam (90th percentile), GRE verbal (99th), SAT (93rd), and multiple medical licensing exams. First truly multimodal frontier model — analyzing images and long documents. OpenAI's technical report: 'sparks of artificial general intelligence.' Multiple law firms, hospitals, and governments integrated it within weeks.",significance:"Established that LLMs had crossed into professional-grade expertise — forcing every industry to reassess AI's role in knowledge work.",tags:["Bar Exam 90th %ile","GRE 99th %ile","Vision + Text","128K context"]},{id:"llama",era:"gen",yearNum:2023.5,year:"2023",emoji:"\uD83E\uDD99",title:"LLaMA — Meta Opens the Frontier",by:"Meta AI Research",desc:"LLaMA-1 leaked (Feb), triggering instant fine-tunes. LLaMA-2 formally released (July) for free commercial use with Microsoft partnership. By 2024, LLaMA 3.1 (405B) 'traded blows with GPT-4.' LLaMA 4 (2025) supports 10M token context and competes with all closed models.",significance:"Broke the compute monopoly — democratized access to frontier-class AI and created the open-weight community (Mistral, Qwen, DeepSeek).",tags:["Open Weights","7B–70B Params","Democratization","Compute Sovereignty"]},{id:"sora",era:"agents",yearNum:2024.1,year:"Feb 2024",emoji:"\uD83C\uDFAC",title:"Sora — Cinematic Text-to-Video AI",by:"OpenAI",desc:"Sora generated up to 60-second videos with cinematic quality, consistent physics, and coherent object permanence. OpenAI called it 'a world simulator.' By 2025, Sora 2 supported 4K resolution and narrative consistency across multi-minute videos.",significance:"AI crossed into professional video production — disrupting a $50B+ industry and raising urgent questions about synthetic media authenticity.",tags:["Text-to-Video","60-sec clips","Physics Understanding"]},{id:"o1",era:"agents",yearNum:2024.7,year:"Sept 2024",emoji:"\uD83E\uDD14",title:"OpenAI o1 — AI That Reasons Before It Answers",by:"OpenAI",desc:"o1 spent compute on internal 'thinking' before answering — scoring at PhD level on physics, chemistry, and biology (GPQA). 83% on IOI (competitive programming) vs. 49th percentile typical. Introduced 'inference-time compute' as a new scaling dimension: more thinking time = better answers.",significance:"Shifted AI from 'how large is the model' to 'how deeply can it think' — the new frontier of AI capability.",tags:["Chain-of-Thought","Inference Compute","PhD Benchmarks","IOI 83%"]},{id:"nobel",era:"agents",yearNum:2024.8,year:"Oct 2024",emoji:"\uD83C\uDFC6",title:"Nobel Prize in Chemistry for AI — A Historic First",by:"Demis Hassabis & John Jumper (DeepMind) + David Baker (UW)",desc:"First Nobel Prize explicitly awarded for AI-driven scientific discovery. AlphaFold Database: 214M structures, 2M users, 190 countries. The Nobel Committee also awarded the 2024 Physics Nobel to Hopfield & Hinton for foundational AI work — two AI Nobels in one year.",significance:"The highest possible validation of AI as a scientific instrument. 'The future is clearly bright for AI in molecular biology.' — Ewan Birney, EMBL.",tags:["Nobel Prize","First AI Nobel","2M researchers","190 Countries"],links:[{label:"EMBL Nobel ↗",url:"https://www.embl.org/news/science-technology/alphafold-wins-nobel-prize-chemistry-2024/"}]},{id:"deepseek",era:"agents",yearNum:2025.1,year:"Jan 2025",emoji:"\uD83C\uDF0F",title:"DeepSeek R1 — Geopolitical AI Earthquake",by:"DeepSeek (Liang Wenfeng, China)",desc:"DeepSeek R1 matched OpenAI o1 at a fraction of the training cost — built under US chip export restrictions using older NVIDIA hardware. Released fully open-source. NVIDIA lost ~$600B in market cap in a single day — the largest single-day market cap loss in history (January 27, 2025).",significance:"Ended the US compute monopoly narrative. Every major AI lab immediately pivoted to efficiency research. Silicon Valley's 'bigger is better' mantra challenged.",tags:["Open Source","Matched o1","NVIDIA −$600B","Efficiency Revolution"]},{id:"agentic",era:"agents",yearNum:2025.5,year:"2025",emoji:"\uD83E\uDD16",title:"Agentic AI Goes Mainstream — AI as Autonomous Worker",by:"Anthropic (Claude Code), OpenAI (Operator), Cursor / Anysphere",desc:"Claude Code (terminal agent), OpenAI Operator (browser automation), and Cursor ($29.3B valuation) shifted LLMs from chat to autonomous workers. Cursor's Composer builds entire applications. Lovable hit $200M ARR in under 1 year. 2025 was called 'the year AI Agents got real.'",significance:"AI stopped being a co-pilot and became a colleague — executing multi-step tasks, writing tests, filing bugs, and deploying code without human intervention at each step.",tags:["AI Agents","Computer Use","Multi-Step Tasks","$29B Cursor Valuation"],links:[{label:"AI Agents 2025 ↗",url:"https://www.hugo.im/posts/ai-agents-year-review-2025"}]},{id:"frontier2026",era:"agents",yearNum:2026,year:"2026 (Now)",emoji:"\uD83C\uDF10",title:"Frontier AI 2026 — Four Labs, Four Specializations",by:"OpenAI, Google DeepMind, Anthropic, xAI, Meta",desc:"GPT-5.4 (74.9% SWE-bench, 92.8% GPQA), Claude Opus 4.6 (best prose, powers Cursor), Gemini 3.1 Pro (94.3% GPQA, 1M context, cheapest API), Grok 4 (75% SWE-bench, real-time X data). Open-weight Llama 4 supports 10M context. AI now impacts medicine, law, science, art, code, and education simultaneously.",significance:"AI has become the most cross-domain transformative technology in human history. The question is no longer 'will AI transform my field?' but 'how fast?'",tags:["74–75% SWE-Bench","91–94% GPQA","1M Context","Multimodal+Agentic"],links:[{label:"2026 Model Comparison ↗",url:"https://gurusup.com/blog/ai-comparisons"}]}]}}]);